/// Extracts the first grapheme cluster of the string.
/// Fails with an error if the string is empty.
#[func]
pub fn first(
    &self,
    /// Number of times to repeat this operation. Fails if exceeds string length.
    #[named]
    #[default(1)]
    repeat: usize,
    /// A set of characters to strip from the start of the string before
    /// extracting the first grapheme cluster(s).
    #[named]
    strip: Option<Str>,
) -> StrResult<Str> {
    let s = match &strip {
        Some(strip) => self.0.trim_start_matches(|c| strip.as_str().contains(c)),
        None => self.0.as_str(),
    };
    let mut graphemes = s.graphemes(true);
    let mut count = 0;
    for _ in 0..repeat {
        if graphemes.next().is_none() {
            if count == 0 {
                return Err(string_is_empty());
            }
            return Err(eco_format!(
                "the string only has {count} grapheme cluster(s), not {repeat}"
            ));
        }
        count += 1;
    }
    let end = s.len() - graphemes.as_str().len();
    Ok(s[..end].into())
}

